/**
 * Generate the Fibonacci (golden-angle) palette — zero dependencies.
 * Carried from the old @vanduo-oss/core repo, trimmed for vd3: this script
 * now writes ONLY the committed DTCG source; the CSS partials that used to be
 * pushed into the framework repo are generated by scripts/build-tokens.mjs.
 *
 * Design:
 *   - Hue identity stays recognizable (red is red, blue is blue) so existing
 *     [data-primary] / [data-neutral] selections keep working, while the brand
 *     hues (primary/secondary) and a dedicated golden accent track are placed by
 *     the GOLDEN ANGLE (~137.5deg) around the wheel — the signature of the system.
 *   - Every family's 10 shades (0 lightest -> 9 darkest) sit on a shared phi
 *     ramp: lightness decreases monotonically and CHROMA peaks at step
 *     round(9 / phi) = 6 (the canonical "main" shade), echoing the golden ratio.
 *   - Colors are computed in OKLCH and converted to sRGB with per-step chroma
 *     clamped into gamut, so every emitted value is a valid in-gamut hex.
 *
 * Output (deterministic):
 *   tokens/primitive/color.fib.tokens.json     committed DTCG source
 */
import { writeFileSync } from "node:fs";
import { fileURLToPath } from "node:url";
import { dirname, resolve } from "node:path";

const here = dirname(fileURLToPath(import.meta.url));
const root = resolve(here, "..");
const tokensDir = resolve(root, "tokens");

const PHI = 1.618033988749895;
const GOLDEN_ANGLE = 137.50776405003785; // 360 * (1 - 1/phi^2)
const PRIMARY_HUE = 200; // OKLCH hue for the brand "water" primary
const GOLDEN_TRACK = 8; // --vd-golden-1..8 (Fibonacci count)

/** Hue placed by the golden angle, k = 0,1,2,... */
const goldenHue = (k) => (((PRIMARY_HUE + k * GOLDEN_ANGLE) % 360) + 360) % 360;

/**
 * Per-family base hue (OKLCH degrees) + peak chroma. Named hues keep their
 * canonical position; brand + golden families are golden-angle placed; neutrals
 * carry only a faint tint.
 */
const FAMILIES = {
  // neutrals (near-achromatic)
  gray: { hue: 250, chroma: 0.006 },
  slate: { hue: 245, chroma: 0.014 },
  charcoal: { hue: 250, chroma: 0.011 },
  zinc: { hue: 286, chroma: 0.005 },
  neutral: { hue: 0, chroma: 0.0 },
  stone: { hue: 70, chroma: 0.008 },
  // brand (golden-angle placed)
  primary: { hue: goldenHue(0), chroma: 0.15 },
  secondary: { hue: goldenHue(1), chroma: 0.15 },
  // status (conventional, recognizable hues)
  danger: { hue: 27, chroma: 0.16 },
  error: { hue: 27, chroma: 0.16 },
  success: { hue: 148, chroma: 0.15 },
  warning: { hue: 75, chroma: 0.15 },
  info: { hue: 250, chroma: 0.15 },
  // named hues (canonical wheel positions)
  red: { hue: 27, chroma: 0.16 },
  orange: { hue: 50, chroma: 0.15 },
  yellow: { hue: 95, chroma: 0.15 },
  lime: { hue: 128, chroma: 0.15 },
  green: { hue: 148, chroma: 0.15 },
  teal: { hue: 178, chroma: 0.14 },
  cyan: { hue: 200, chroma: 0.14 },
  blue: { hue: 250, chroma: 0.15 },
  indigo: { hue: 272, chroma: 0.15 },
  violet: { hue: 295, chroma: 0.15 },
  grape: { hue: 325, chroma: 0.15 },
  pink: { hue: 352, chroma: 0.15 },
};

// Lightness ramp (step 0 -> 9), monotonically decreasing.
const L_RAMP = [0.972, 0.93, 0.872, 0.806, 0.732, 0.66, 0.586, 0.5, 0.41, 0.32];
// Chroma multiplier per step — peaks at round(9/phi) = 6 (the "main" shade).
const C_RAMP = [0.16, 0.34, 0.56, 0.76, 0.9, 0.99, 1.0, 0.9, 0.72, 0.54];
const MAIN_STEP = Math.round(9 / PHI); // 6

const clamp01 = (x) => (x < 0 ? 0 : x > 1 ? 1 : x);

/** OKLCH -> linear sRGB (Bjorn Ottosson). Returns raw (possibly out-of-gamut). */
const oklchToLinear = (L, C, hDeg) => {
  const h = (hDeg * Math.PI) / 180;
  const a = C * Math.cos(h);
  const b = C * Math.sin(h);
  const l_ = L + 0.3963377774 * a + 0.2158037573 * b;
  const m_ = L - 0.1055613458 * a - 0.0638541728 * b;
  const s_ = L - 0.0894841775 * a - 1.291485548 * b;
  const l = l_ * l_ * l_;
  const m = m_ * m_ * m_;
  const s = s_ * s_ * s_;
  return [
    4.0767416621 * l - 3.3077115913 * m + 0.2309699292 * s,
    -1.2684380046 * l + 2.6097574011 * m - 0.3413193965 * s,
    -0.0041960863 * l - 0.7034186147 * m + 1.707614701 * s,
  ];
};

const EPS = 1e-4;
const inGamut = ([r, g, b]) =>
  r >= -EPS &&
  r <= 1 + EPS &&
  g >= -EPS &&
  g <= 1 + EPS &&
  b >= -EPS &&
  b <= 1 + EPS;

const gamma = (c) =>
  c <= 0.0031308 ? 12.92 * c : 1.055 * Math.pow(c, 1 / 2.4) - 0.055;

const toHex = ([r, g, b]) =>
  "#" +
  [r, g, b]
    .map((c) =>
      Math.round(clamp01(gamma(clamp01(c))) * 255)
        .toString(16)
        .padStart(2, "0"),
    )
    .join("");

/** Largest in-gamut chroma <= C at (L, hue), via binary search; then to hex. */
const oklchToHex = (L, C, hue) => {
  if (inGamut(oklchToLinear(L, C, hue))) return toHex(oklchToLinear(L, C, hue));
  let lo = 0;
  let hi = C;
  for (let i = 0; i < 32; i++) {
    const mid = (lo + hi) / 2;
    if (inGamut(oklchToLinear(L, mid, hue))) lo = mid;
    else hi = mid;
  }
  return toHex(oklchToLinear(L, lo, hue));
};

/** Full 0..9 scale for a family. */
const scaleFor = ({ hue, chroma }) =>
  L_RAMP.map((L, i) => oklchToHex(L, chroma * C_RAMP[i], hue));

// ── Build the DTCG tree (mirrors color.tokens.json shape). ──
const colorLeaf = (hex) => ({ $type: "color", $value: hex });
const tree = {
  $description:
    "Primitive palette — Fibonacci (golden-angle) scales. Generated by scripts/generate-fib-palette.mjs; do not edit by hand.",
};
for (const [family, def] of Object.entries(FAMILIES)) {
  const scale = scaleFor(def);
  tree[family] = Object.fromEntries(
    scale.map((hex, i) => [String(i), colorLeaf(hex)]),
  );
}
// Golden accent track: golden-1..N, each the "main" shade of a golden-angle hue.
const golden = {};
for (let k = 0; k < GOLDEN_TRACK; k++) {
  const hex = oklchToHex(
    L_RAMP[MAIN_STEP],
    0.16 * C_RAMP[MAIN_STEP],
    goldenHue(k),
  );
  golden[String(k + 1)] = colorLeaf(hex);
}
tree.golden = golden;

const fibPath = resolve(tokensDir, "primitive/color.fib.tokens.json");
writeFileSync(fibPath, JSON.stringify(tree, null, 2) + "\n");

console.log(
  `Generated ${Object.keys(FAMILIES).length + 1} families -> tokens/primitive/color.fib.tokens.json`,
);
